1965     return getPredicateAt(CmpInst::getSwappedPredicate(Pred), RHS, C, CxtI,
1966                           UseBlockValue);
1967 
1968   // Got two non-Constant values. Try to determine the comparison results based
1969   // on the block values of the two operands, e.g. because they have
1970   // non-overlapping ranges.
1971   if (UseBlockValue) {
1972     Module *M = CxtI->getModule();
1973     ValueLatticeElement L =
1974         getOrCreateImpl(M).getValueInBlock(LHS, CxtI->getParent(), CxtI);
1975     if (L.isOverdefined())
1976       return LazyValueInfo::Unknown;
1977 
1978     ValueLatticeElement R =
1979         getOrCreateImpl(M).getValueInBlock(RHS, CxtI->getParent(), CxtI);
1980     Type *Ty = CmpInst::makeCmpResultType(LHS->getType());
1981     if (Constant *Res = L.getCompare((CmpInst::Predicate)P, Ty, R,
1982                                      M->getDataLayout())) {
1983       if (Res->isNullValue())
1984         return LazyValueInfo::False;
1985       if (Res->isOneValue())
1986         return LazyValueInfo::True;
1987     }
1988   }
1989   return LazyValueInfo::Unknown;
