1569 ValueLatticeElement LazyValueInfoImpl::getValueAtUse(const Use &U) {
1570   Value *V = U.get();
1571   auto *CxtI = cast<Instruction>(U.getUser());
1572   ValueLatticeElement VL = getValueInBlock(V, CxtI->getParent(), CxtI);
1573 
1574   // Check whether the only (possibly transitive) use of the value is in a
1575   // position where V can be constrained by a select or branch condition.
1576   const Use *CurrU = &U;
1577   // TODO: Increase limit?
1578   const unsigned MaxUsesToInspect = 3;
1579   for (unsigned I = 0; I < MaxUsesToInspect; ++I) {
1580     std::optional<ValueLatticeElement> CondVal;
1581     auto *CurrI = cast<Instruction>(CurrU->getUser());
1582     if (auto *SI = dyn_cast<SelectInst>(CurrI)) {
1583       // If the value is undef, a different value may be chosen in
1584       // the select condition and at use.
1585       if (!isGuaranteedNotToBeUndef(SI->getCondition(), AC))
1586         break;
1587       if (CurrU->getOperandNo() == 1)
1588         CondVal =
1589             *getValueFromCondition(V, SI->getCondition(), /*IsTrueDest*/ true,
1590                                    /*UseBlockValue*/ false);
1591       else if (CurrU->getOperandNo() == 2)
1592         CondVal =
1593             *getValueFromCondition(V, SI->getCondition(), /*IsTrueDest*/ false,
1594                                    /*UseBlockValue*/ false);
1595     } else if (auto *PHI = dyn_cast<PHINode>(CurrI)) {
1596       // TODO: Use non-local query?
1597       CondVal = *getEdgeValueLocal(V, PHI->getIncomingBlock(*CurrU),
1598                                    PHI->getParent(), /*UseBlockValue*/ false);
1599     }
1600     if (CondVal)
1601       VL = intersect(VL, *CondVal);
1602 
1603     // Only follow one-use chain, to allow direct intersection of conditions.
1604     // If there are multiple uses, we would have to intersect with the union of
1605     // all conditions at different uses.
1606     // Stop walking if we hit a non-speculatable instruction. Even if the
1607     // result is only used under a specific condition, executing the
1608     // instruction itself may cause side effects or UB already.
1609     // This also disallows looking through phi nodes: If the phi node is part
1610     // of a cycle, we might end up reasoning about values from different cycle
1611     // iterations (PR60629).
1612     if (!CurrI->hasOneUse() || !isSafeToSpeculativelyExecute(CurrI))
1613       break;
1614     CurrU = &*CurrI->use_begin();
1615   }
1616   return VL;
1617 }
