1308 // Return true if the instruction type of Val is supported by
1309 // constantFoldUser(). Currently CastInst, BinaryOperator and FreezeInst only.
1310 // Call this before calling constantFoldUser() to find out if it's even worth
1311 // attempting to call it.
1312 static bool isOperationFoldable(User *Usr) {
1313   return isa<CastInst>(Usr) || isa<BinaryOperator>(Usr) || isa<FreezeInst>(Usr);
1314 }
