1316 // Check if Usr can be simplified to an integer constant when the value of one
1317 // of its operands Op is an integer constant OpConstVal. If so, return it as an
1318 // lattice value range with a single element or otherwise return an overdefined
1319 // lattice value.
1320 static ValueLatticeElement constantFoldUser(User *Usr, Value *Op,
1321                                             const APInt &OpConstVal,
1322                                             const DataLayout &DL) {
1323   assert(isOperationFoldable(Usr) && "Precondition");
1324   Constant* OpConst = Constant::getIntegerValue(Op->getType(), OpConstVal);
1325   // Check if Usr can be simplified to a constant.
1326   if (auto *CI = dyn_cast<CastInst>(Usr)) {
1327     assert(CI->getOperand(0) == Op && "Operand 0 isn't Op");
1328     if (auto *C = dyn_cast_or_null<ConstantInt>(
1329             simplifyCastInst(CI->getOpcode(), OpConst,
1330                              CI->getDestTy(), DL))) {
1331       return ValueLatticeElement::getRange(ConstantRange(C->getValue()));
1332     }
1333   } else if (auto *BO = dyn_cast<BinaryOperator>(Usr)) {
1334     bool Op0Match = BO->getOperand(0) == Op;
1335     bool Op1Match = BO->getOperand(1) == Op;
1336     assert((Op0Match || Op1Match) &&
1337            "Operand 0 nor Operand 1 isn't a match");
1338     Value *LHS = Op0Match ? OpConst : BO->getOperand(0);
1339     Value *RHS = Op1Match ? OpConst : BO->getOperand(1);
1340     if (auto *C = dyn_cast_or_null<ConstantInt>(
1341             simplifyBinOp(BO->getOpcode(), LHS, RHS, DL))) {
1342       return ValueLatticeElement::getRange(ConstantRange(C->getValue()));
1343     }
1344   } else if (isa<FreezeInst>(Usr)) {
1345     assert(cast<FreezeInst>(Usr)->getOperand(0) == Op && "Operand 0 isn't Op");
1346     return ValueLatticeElement::getRange(ConstantRange(OpConstVal));
1347   }
1348   return ValueLatticeElement::getOverdefined();
1349 }
