1351 /// Compute the value of Val on the edge BBFrom -> BBTo.
1352 std::optional<ValueLatticeElement>
1353 LazyValueInfoImpl::getEdgeValueLocal(Value *Val, BasicBlock *BBFrom,
1354                                      BasicBlock *BBTo, bool UseBlockValue) {
1355   // TODO: Handle more complex conditionals. If (v == 0 || v2 < 1) is false, we
1356   // know that v != 0.
1357   if (BranchInst *BI = dyn_cast<BranchInst>(BBFrom->getTerminator())) {
1358     // If this is a conditional branch and only one successor goes to BBTo, then
1359     // we may be able to infer something from the condition.
1360     if (BI->isConditional() &&
1361         BI->getSuccessor(0) != BI->getSuccessor(1)) {
1362       bool isTrueDest = BI->getSuccessor(0) == BBTo;
1363       assert(BI->getSuccessor(!isTrueDest) == BBTo &&
1364              "BBTo isn't a successor of BBFrom");
1365       Value *Condition = BI->getCondition();
1366 
1367       // If V is the condition of the branch itself, then we know exactly what
1368       // it is.
1369       if (Condition == Val)
1370         return ValueLatticeElement::get(ConstantInt::get(
1371                               Type::getInt1Ty(Val->getContext()), isTrueDest));
1372 
1373       // If the condition of the branch is an equality comparison, we may be
1374       // able to infer the value.
1375       std::optional<ValueLatticeElement> Result =
1376           getValueFromCondition(Val, Condition, isTrueDest, UseBlockValue);
1377       if (!Result)
1378         return std::nullopt;
1379 
1380       if (!Result->isOverdefined())
1381         return Result;
1382 
1383       if (User *Usr = dyn_cast<User>(Val)) {
1384         assert(Result->isOverdefined() && "Result isn't overdefined");
1385         // Check with isOperationFoldable() first to avoid linearly iterating
1386         // over the operands unnecessarily which can be expensive for
1387         // instructions with many operands.
1388         if (isa<IntegerType>(Usr->getType()) && isOperationFoldable(Usr)) {
1389           const DataLayout &DL = BBTo->getModule()->getDataLayout();
1390           if (usesOperand(Usr, Condition)) {
1391             // If Val has Condition as an operand and Val can be folded into a
1392             // constant with either Condition == true or Condition == false,
1393             // propagate the constant.
1394             // eg.
1395             //   ; %Val is true on the edge to %then.
1396             //   %Val = and i1 %Condition, true.
1397             //   br %Condition, label %then, label %else
1398             APInt ConditionVal(1, isTrueDest ? 1 : 0);
1399             Result = constantFoldUser(Usr, Condition, ConditionVal, DL);
1400           } else {
1401             // If one of Val's operand has an inferred value, we may be able to
1402             // infer the value of Val.
1403             // eg.
1404             //    ; %Val is 94 on the edge to %then.
1405             //    %Val = add i8 %Op, 1
1406             //    %Condition = icmp eq i8 %Op, 93
1407             //    br i1 %Condition, label %then, label %else
1408             for (unsigned i = 0; i < Usr->getNumOperands(); ++i) {
1409               Value *Op = Usr->getOperand(i);
1410               ValueLatticeElement OpLatticeVal = *getValueFromCondition(
1411                   Op, Condition, isTrueDest, /*UseBlockValue*/ false);
1412               if (std::optional<APInt> OpConst =
1413                       OpLatticeVal.asConstantInteger()) {
1414                 Result = constantFoldUser(Usr, Op, *OpConst, DL);
1415                 break;
1416               }
1417             }
1418           }
1419         }
1420       }
1421       if (!Result->isOverdefined())
1422         return Result;
1423     }
1424   }
1425 
1426   // If the edge was formed by a switch on the value, then we may know exactly
1427   // what it is.
1428   if (SwitchInst *SI = dyn_cast<SwitchInst>(BBFrom->getTerminator())) {
1429     Value *Condition = SI->getCondition();
1430     if (!isa<IntegerType>(Val->getType()))
1431       return ValueLatticeElement::getOverdefined();
1432     bool ValUsesConditionAndMayBeFoldable = false;
1433     if (Condition != Val) {
1434       // Check if Val has Condition as an operand.
1435       if (User *Usr = dyn_cast<User>(Val))
1436         ValUsesConditionAndMayBeFoldable = isOperationFoldable(Usr) &&
1437             usesOperand(Usr, Condition);
1438       if (!ValUsesConditionAndMayBeFoldable)
1439         return ValueLatticeElement::getOverdefined();
1440     }
1441     assert((Condition == Val || ValUsesConditionAndMayBeFoldable) &&
1442            "Condition != Val nor Val doesn't use Condition");
1443 
1444     bool DefaultCase = SI->getDefaultDest() == BBTo;
1445     unsigned BitWidth = Val->getType()->getIntegerBitWidth();
1446     ConstantRange EdgesVals(BitWidth, DefaultCase/*isFullSet*/);
1447 
1448     for (auto Case : SI->cases()) {
1449       APInt CaseValue = Case.getCaseValue()->getValue();
1450       ConstantRange EdgeVal(CaseValue);
1451       if (ValUsesConditionAndMayBeFoldable) {
1452         User *Usr = cast<User>(Val);
1453         const DataLayout &DL = BBTo->getModule()->getDataLayout();
1454         ValueLatticeElement EdgeLatticeVal =
1455             constantFoldUser(Usr, Condition, CaseValue, DL);
1456         if (EdgeLatticeVal.isOverdefined())
1457           return ValueLatticeElement::getOverdefined();
1458         EdgeVal = EdgeLatticeVal.getConstantRange();
1459       }
1460       if (DefaultCase) {
1461         // It is possible that the default destination is the destination of
1462         // some cases. We cannot perform difference for those cases.
1463         // We know Condition != CaseValue in BBTo.  In some cases we can use
1464         // this to infer Val == f(Condition) is != f(CaseValue).  For now, we
1465         // only do this when f is identity (i.e. Val == Condition), but we
1466         // should be able to do this for any injective f.
1467         if (Case.getCaseSuccessor() != BBTo && Condition == Val)
1468           EdgesVals = EdgesVals.difference(EdgeVal);
1469       } else if (Case.getCaseSuccessor() == BBTo)
1470         EdgesVals = EdgesVals.unionWith(EdgeVal);
1471     }
1472     return ValueLatticeElement::getRange(std::move(EdgesVals));
1473   }
1474   return ValueLatticeElement::getOverdefined();
1475 }
