1477 /// Compute the value of Val on the edge BBFrom -> BBTo or the value at
1478 /// the basic block if the edge does not constrain Val.
1479 std::optional<ValueLatticeElement>
1480 LazyValueInfoImpl::getEdgeValue(Value *Val, BasicBlock *BBFrom,
1481                                 BasicBlock *BBTo, Instruction *CxtI) {
1482   // If already a constant, there is nothing to compute.
1483   if (Constant *VC = dyn_cast<Constant>(Val))
1484     return ValueLatticeElement::get(VC);
1485 
1486   std::optional<ValueLatticeElement> LocalResult =
1487       getEdgeValueLocal(Val, BBFrom, BBTo, /*UseBlockValue*/ true);
1488   if (!LocalResult)
1489     return std::nullopt;
1490 
1491   if (hasSingleValue(*LocalResult))
1492     // Can't get any more precise here
1493     return LocalResult;
1494 
1495   std::optional<ValueLatticeElement> OptInBlock =
1496       getBlockValue(Val, BBFrom, BBFrom->getTerminator());
1497   if (!OptInBlock)
1498     return std::nullopt;
1499   ValueLatticeElement &InBlock = *OptInBlock;
1500 
1501   // We can use the context instruction (generically the ultimate instruction
1502   // the calling pass is trying to simplify) here, even though the result of
1503   // this function is generally cached when called from the solve* functions
1504   // (and that cached result might be used with queries using a different
1505   // context instruction), because when this function is called from the solve*
1506   // functions, the context instruction is not provided. When called from
1507   // LazyValueInfoImpl::getValueOnEdge, the context instruction is provided,
1508   // but then the result is not cached.
1509   intersectAssumeOrGuardBlockValueConstantRange(Val, InBlock, CxtI);
1510 
1511   return intersect(*LocalResult, InBlock);
1512 }
